8151	\begin{lemma}
8152	
8153	\leanok
8154	[Push--pull over the {\v C}ech backbone is the product over intersection opens]
8155	  \label{lem:pushPull_sigma_iso}
8156	  \lean{AlgebraicGeometry.pushPull_sigma_iso}
8157	  \uses{def:push_pull_obj, lem:cech_backbone_left_sigma, lem:pushPull_coprod_prod}
8158	  With the notation of Lemma~\ref{lem:cech_backbone_left_sigma}, the push--pull object on
8159	  the degree-\(p\) backbone decomposes as a product over the multi-indices:
8160	  \[
8161	    \operatorname{pushPullObj}\mathcal{F}\,Y_p
8162	      \;\cong\;
8163	    \prod_{\sigma : \mathrm{Fin}(p+1) \to I}
8164	      \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk} j_\sigma)
8165	    \qquad \text{in } X.\mathrm{Modules},
8166	  \]
8167	  equivalently \((q_p)_*\,(q_p)^*\mathcal{F} \cong \prod_\sigma (j_\sigma)_*\,
8168	  (j_\sigma)^*\mathcal{F}\).
8169	\end{lemma}
8170	\begin{proof}
8171	  \uses{lem:cech_backbone_left_sigma, lem:pushPull_coprod_prod}
8172	  By Lemma~\ref{lem:cech_backbone_left_sigma} the backbone \(Y_p\) is the coproduct
8173	  \(\coprod_\sigma U_\sigma\) with structure map \(q_p = \operatorname{Sigma.desc}(\sigma
8174	  \mapsto j_\sigma)\). Apply Lemma~\ref{lem:pushPull_coprod_prod} to this coproduct family,
8175	  with the finite multi-index type \(\sigma : \mathrm{Fin}(p+1) \to I\) as the index and the
8176	  intersection-open legs \(\operatorname{Over.mk} j_\sigma\), to obtain the asserted product
8177	  decomposition.
8178	\end{proof}
