8180	\begin{lemma}
8181	
8182	\leanok
8183	[Sections of one push--pull leg over an open]
8184	  \label{lem:pushPull_leg_sections}
8185	  \lean{AlgebraicGeometry.pushPull_leg_sections}
8186	  \uses{def:push_pull_obj, def:cech_free_presheaf_complex, lem:pushforward_obj_obj_mathlib,
8187	    lem:restrictFunctorIsoPullback_mathlib, lem:restrict_obj_mathlib}
8188	  Let \(j_\sigma : U_\sigma \hookrightarrow X\) be the open immersion of the intersection
8189	  open \(U_\sigma = \operatorname{coverInterOpen}\mathcal{U}\,\sigma\), and let
8190	  \(V \subseteq X\) be an open. Then there is a natural isomorphism of section groups
8191	  \[
8192	    \Gamma\bigl(V,\, \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk}
8193	      j_\sigma)\bigr)
8194	      \;\cong\;
8195	    \Gamma\bigl(U_\sigma \cap V,\, \mathcal{F}\bigr).
8196	  \]
8197	\end{lemma}
8198	\begin{proof}
8199	  \uses{lem:pushforward_obj_obj_mathlib, lem:restrictFunctorIsoPullback_mathlib,
8200	    lem:restrict_obj_mathlib}
8201	  This follows from three standard identifications. First, the leg is
8202	  \((j_\sigma)_*\,(j_\sigma)^*\mathcal{F}\); pushforward sections are computed by preimage,
8203	  \(\Gamma\bigl(V, (j_\sigma)_* N\bigr) = \Gamma\bigl(j_\sigma^{-1}(V), N\bigr)\)
8204	  (Lemma~\ref{lem:pushforward_obj_obj_mathlib}, an equality), applied with \(N =
8205	  (j_\sigma)^*\mathcal{F}\). Second, pullback along the open immersion \(j_\sigma\) is the
8206	  restriction functor: \((j_\sigma)^*\mathcal{F} \cong \mathcal{F}.\operatorname{restrict}
8207	  j_\sigma\) by Lemma~\ref{lem:restrictFunctorIsoPullback_mathlib}. Third, the sections of a
8208	  restricted module over \(j_\sigma^{-1}(V)\) are the sections of \(\mathcal{F}\) over the
8209	  image open (Lemma~\ref{lem:restrict_obj_mathlib}, an equality): \(\Gamma\bigl(j_\sigma^{-1}
8210	  (V), \mathcal{F}.\operatorname{restrict} j_\sigma\bigr) = \Gamma\bigl(j_\sigma\bigl(
8211	  j_\sigma^{-1}(V)\bigr), \mathcal{F}\bigr) = \Gamma\bigl(U_\sigma \cap V, \mathcal{F}\bigr)\),
8212	  the last equality because the image of the preimage of \(V\) under the open immersion
8213	  \(j_\sigma : U_\sigma \hookrightarrow X\) is exactly \(U_\sigma \cap V\). Composing the
8214	  three gives the stated isomorphism.
8215	\end{proof}
