8217	\begin{lemma}
8218	
8219	\leanok
8220	[Degreewise section identification of the {\v C}ech backbone]
8221	  \label{lem:pushPull_eval_prod_iso}
8222	  \lean{AlgebraicGeometry.pushPull_eval_prod_iso}
8223	  \uses{lem:pushPull_sigma_iso, lem:pushPull_leg_sections,
8224	    lem:evaluation_preserves_products_mathlib}
8225	  For an open \(V \subseteq X\) and every degree \(p\) there is an isomorphism
8226	  \[
8227	    \Gamma\bigl(V,\, \operatorname{pushPullObj}\mathcal{F}\,Y_p\bigr)
8228	      \;\cong\;
8229	    \prod_{\sigma : \mathrm{Fin}(p+1) \to I}
8230	      \Gamma\bigl(\operatorname{coverInterOpen}\mathcal{U}\,\sigma \cap V,\, \mathcal{F}\bigr).
8231	  \]
8232	\end{lemma}
8233	\begin{proof}
8234	  \uses{lem:pushPull_sigma_iso, lem:pushPull_leg_sections,
8235	    lem:evaluation_preserves_products_mathlib}
8236	  Combine the product decomposition of the backbone push--pull object
8237	  (Lemma~\ref{lem:pushPull_sigma_iso}), \(\operatorname{pushPullObj}\mathcal{F}\,Y_p \cong
8238	  \prod_\sigma \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk} j_\sigma)\),
8239	  with the fact that the section (evaluation-at-\(V\)) functor on \(X.\mathrm{Modules}\)
8240	  preserves products (Lemma~\ref{lem:evaluation_preserves_products_mathlib}): \(\Gamma(V,
8241	  \prod_\sigma N_\sigma) \cong \prod_\sigma \Gamma(V, N_\sigma)\). This reduces the
8242	  left-hand side to \(\prod_\sigma \Gamma\bigl(V, \operatorname{pushPullObj}\mathcal{F}\,
8243	  (\operatorname{Over.mk} j_\sigma)\bigr)\), and the per-leg section identification
8244	  (Lemma~\ref{lem:pushPull_leg_sections}) rewrites each factor as \(\Gamma(U_\sigma \cap V,
8245	  \mathcal{F})\).
8246	\end{proof}
